var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇게 직접 다녀오실 정도면 꽤나 중요한 물건이었나 보죠?","JPN":"自ら出向くなんて、よっぽど大事な品だったのですね。","ENG":"You went to pick this up yourself. It's so valuable, huh?","TWN":"是什麼重要的東西讓您親自去拿？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......피난을 떠날 때 중요한 걸 전부 챙겨갈 수는 없는 법 아니겠나.","JPN":"……避難する時は大事なモノの中で取捨選択を迫られる。","ENG":"You can't take everything with you when you leave in a hurry.","TWN":"……避難時總不能把所有重要的東西都帶在身上。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 잃어버린 것들 중 하나가 우연한 계기로 다시 내게 돌아온 셈이지.","JPN":"そうやって一度失くしたものが、たまたま戻ってきてくれたということだ。","ENG":"This is one of the things that I cherished and lost, and somehow it has found its way back to me.","TWN":"可以說有一個沒來得及帶在身上的東西現在又回到了我的身邊。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"중요한 것치곤 상태가 말이 아닌 것 같던데요.","JPN":"その割には状態がよろしくないようですが。","ENG":"It doesn't look like it's been cherished since you lost it.","TWN":"這個從狀態看，可不像是重要的東西。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래, 아무래도 해적들에게 끌려오기 전에 저항이 있었던 모양이야.","JPN":"まあな。どうやら海賊どもに連れていかれる前に\\n抵抗したようだ。","ENG":"No. Something must have happened before it was found by the pirates.","TWN":"的確，應該是被海盜們帶走之前有過抵抗。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"정확한 상태가 어떤지는 지금부터 확인해봐야겠지.","JPN":"どんな状態かは、これから精査してみないとな。","ENG":"I won't know its exact condition until I look into it.","TWN":"我現在要檢查一下它的具體狀態。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"엔지니어를 부를까요?","JPN":"エンジニアを呼びましょうか？","ENG":"Want me to call in some engineers?","TWN":"要不要叫工程師？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니야. 이거면 충분하네.","JPN":"いや、これで十分だ。","ENG":"No. This should do.","TWN":"不，有這個就夠了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네? 그건 그냥 손을 대는 것뿐......","JPN":"はい？　ただ手を当てるだけじゃ……","ENG":"Sorry? That's just a touch of your hand—","TWN":"嗯？只是用手去觸摸……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"관리자 권한 확인, 시스템 온라인.","JPN":"管理者権限を確認、システムオンライン。","ENG":"Administrator authorization confirmed. System online.","TWN":"確認管理者許可權，系統線上。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SYS_START1"},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"동력 상태 양호.","JPN":"動力状態、良好。","ENG":"Energy level: Normal.","TWN":"動力狀態良好。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"자동 수복 기능 활성화.","JPN":"自動修復機能を活性化。","ENG":"Activating auto-recovery function...","TWN":"啟動自動修復功能。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"반갑군. 내가 누군지 알아보겠나?","JPN":"久しぶりだな。私のことがわかるかい？","ENG":"Good to see you again. Remember me?","TWN":"你好啊，你能認出我嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SIGMA_RAS_GIRL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SIGMA_RAS_GIRL_NULL","text":{"KOREA":"......내 아빠야.","JPN":"……私のパパ。","ENG":"You're my daddy.","TWN":"……是爸爸。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아빠라고?","JPN":"パパだって？","ENG":"Daddy?","TWN":"爸爸？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......아빠?","JPN":"……パパ？","ENG":"... Daddy?","TWN":"……爸爸？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SIGMA_RAS_GIRL_NULL","text":{"KOREA":"응, 날 만들어준 사람이니까 아빠잖아.","JPN":"うん。私のことをつくってくれたから、パパだよ。","ENG":"Yes. You're the one who made me. You're my daddy.","TWN":"嗯，是你將我創造出來的，所以是爸爸。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SIGMA_RAS_GIRL_NULL","text":{"KOREA":"보고 싶었어! 아빠!","JPN":"会いたかったよ！　パパ！","ENG":"I missed you, Daddy!","TWN":"我好想你！爸爸！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SIGMA_RAS_GIRL_NULL","text":{"KOREA":"아빠도 내가 보고 싶었지?","JPN":"パパも私に会いたかったでしょ？","ENG":"Did you miss me too?","TWN":"爸爸也想我嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"왜, 왜 그런 눈으로 바라보나! 난 모르는 일이야!","JPN":"な、なぜそんな目で見る！　変な想像を\\n膨らませないように！","ENG":"D-don't look at me like that! I had nothing to do with this!","TWN":"別、別用那樣的眼神看我！我也不知道是怎麼回事！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아, 네. 물론 그러시겠죠. 어디서 많이 듣던 것 같은 변명이네요.","JPN":"はいはい、そうですね。どこかで聞いたような\\n言い訳ですこと。","ENG":"Yes, sure. Of course. I've heard that before.","TWN":"喔，是，那當然。很常用的辯解台詞。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그나저나 이런 취향이 있으실 줄은 몰랐군요. 직접 만든 거라고 하셨죠? 세상에......","JPN":"こんな趣味があっただなんて。ご自分でつくられた\\nとおっしゃってましたよね？　まさか、こんな……","ENG":"By the way, I didn't know you were interested in this sort of role play. You made her yourself, huh? My goodness!","TWN":"沒想到您有這樣的癖好。是您親自製作的？天啊……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그, 그럴리가! 굳이 어느 쪽이냐고 한다면 난 좀 더......","JPN":"そ、そんなわけあるか！　どっちかというと私はもう少し……","ENG":"W-what are you talking about? If you ask me, I prefer more...","TWN":"怎、怎麼可能！如果非要我說，我喜歡更……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"좀 더......?","JPN":"もう少し……？","ENG":"You prefer... what?","TWN":"喜歡更……？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아, 아니 됐어. 그보다 잠시 자릴 비워주겠나?","JPN":"い、いや、いいんだ。それよりしばらく外してくれるか？","ENG":"Ugh, forget it. Could you excuse us for a moment?","TWN":"不，算了。能請你出去一下嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"대체 무슨 일이 일어났던 건지 분석을 좀 해봐야겠어.","JPN":"一体何があったのか、分析をしてみないとな。","ENG":"I need to find out what happened to her.","TWN":"我必須分析一下到底發生了什麼事。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......그러죠. 혼자만의 시간이 좀 필요하실 것 같네요.","JPN":"……いいでしょう、一人だけの時間が必要そうですからね。","ENG":"Sure. I can tell you definitely need some time alone.","TWN":"……好，我想您確實需要獨自待一會。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_DOOR_WOOD"},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"역시 오랫동안 버려져 있던 탓에 명령 알고리즘에 문제가 있었나.","JPN":"長らく放置されていたせいで、命令アルゴリズムに\\n問題が生じたのか。","ENG":"I guess something happened to her command algorithms during the time she was left alone.","TWN":"是因為被廢棄太久，規則系統發生問題了嗎。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_15"},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"강한 침식파의 영향으로 시스템이 불안정한 상태에서 독립 임무를 강행한 것 같군.","JPN":"強い侵食波を受けてシステムが不安定な状態の中、\\n単独任務を強行したようだ。","ENG":"She must have carried out missions on her own while her system was unstable due to the powerful Corruption rays around her.","TWN":"好像是在強大侵蝕波的影響中，系統在不穩定的狀態下獨自進行了任務。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서 주요데이터 소실은 물론, 인공지능에도 타격이 간 모양이고.","JPN":"そのせいで主要データの消失はもちろん、\\n人工知能にもダメージがあったんだな。","ENG":"That explains the loss of main data and the damage to her AI.","TWN":"所以才導致主要資料丟失，人工智慧也受到了影響。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"데이터가 보전되어있었다면 많은 도움이 됐을 텐데 아쉽게 됐는걸.","JPN":"データが保全されていれば役に立っただろうに、\\nもったいないな。","ENG":"I wish her data had survived. It would have been very helpful.","TWN":"要是資料沒丟失就好了，一定能幫上不少忙。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SIGMA_RAS_GIRL_NULL","text":{"KOREA":"아빠, 내가 뭘 잘못한 거야?","JPN":"パパ。私、何かいけないことしたの？","ENG":"Daddy, did I do something wrong?","TWN":"爸爸，是我做錯了什麼嘛？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......아니야. 이렇게 무사히 돌아와준 것만으로도 기쁘단다.","JPN":"……いや、こうやって無事に戻って\\nきてくれただけで嬉しいよ。","ENG":"... No, not at all. I'm glad you safely came back to me.","TWN":"……不，你能平安回來我就很高興了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 날 부를 때의 호칭은......","JPN":"あと、私の呼び名は……","ENG":"And you should call me...","TWN":"然後你叫我的時候不要……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......아니, 괜찮겠지.","JPN":"……いや、いいだろう。","ENG":"No, never mind.","TWN":"……不，沒事了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_GIRL_NULL","text":{"KOREA":"나 아빠가 돌아오지 않아서......","JPN":"私ね、パパが帰ってくるまで……","ENG":"Daddy, I waited for you...","TWN":"我等爸爸回來……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SIGMA_RAS_GIRL_NULL","text":{"KOREA":"정말 오랫동안 기다렸어.","JPN":"本当に長い時間待ってたわ。","ENG":"for a long, long time.","TWN":"等了很長時間。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SIGMA_RAS_GIRL_NULL","text":{"KOREA":"나 아빠 말 잘 듣고 열심히 할게.","JPN":"私、パパの言うことよく聞いて頑張るから。","ENG":"I promise I'll be a good girl.","TWN":"我以後會很乖很努力的。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SIGMA_RAS_GIRL_NULL","text":{"KOREA":"이제 말없이 떠나지 않을 거지?","JPN":"また黙っていなくなったりしないよね？","ENG":"You're not going to leave me again, are you?","TWN":"不要再突然離開我了，好嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래......","JPN":"ああ……","ENG":"No.","TWN":"是這樣啊……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"물론이고 말고.","JPN":"もちろんだとも。","ENG":"Of course not.","TWN":"當然。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};